const initListener=async()=>{const e=document.getElementById("menu-toggle"),t=document.getElementById("nav-links");e.addEventListener("click",()=>{const n=t.classList.toggle("active");e.setAttribute("aria-expanded",String(n))}),document.querySelectorAll(".nav-links a, .floating-rsvp").forEach(n=>{n.addEventListener("click",a=>{a.preventDefault(),t.classList.remove("active"),e.setAttribute("aria-expanded","false");const o=n.getAttribute("href"),s=document.querySelector(o);s&&s.scrollIntoView({behavior:"smooth",block:"start"})})}),window.addEventListener("scroll",()=>{const e=document.querySelector(".navbar");window.scrollY>50?(e.style.background="rgba(247,248,246,0.96)",e.style.boxShadow="0 4px 20px rgba(0,0,0,0.05)"):(e.style.background="rgba(247,248,246,0.90)",e.style.boxShadow="none")});const n=new IntersectionObserver(e=>{e.forEach(e=>{const t=e.target.querySelector("iframe");t&&(e.isIntersecting?t.style.display="block":t.style.display="none")})},{root:null,threshold:.2,rootMargin:"200px 0px"});document.querySelectorAll(".iframe-limit").forEach(e=>n.observe(e));const a=document.querySelectorAll(".map-btn"),o=document.getElementById("ceremony-map"),s=document.getElementById("reception-map");a.forEach(e=>{e.addEventListener("click",()=>{const t=e.dataset.map;a.forEach(e=>e.classList.remove("active")),e.classList.add("active"),o.classList.remove("active-map"),s.classList.remove("active-map"),"ceremony"===t?o.classList.add("active-map"):s.classList.add("active-map")})})};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",initListener):initListener();